+  private getKeysetPagination(opts: CrudOptions) {
+    const cursorSupplied = opts.cursor !== undefined;
+    if (cursorSupplied && !opts.orderBy) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (cursorSupplied && opts.offset !== undefined) {
+      throw new BadRequestException('cursor cannot be used with offset');
+    }
+    if (!opts.orderBy || !opts.limit) {
+      return undefined;
+    }
+
+    const orderBy = this.normalizeCursorOrderBy(opts.orderBy);
+    const cursor = cursorSupplied
+      ? this.decodeCursor(opts.cursor, orderBy)
+      : undefined;
+    return { orderBy, cursor, limit: opts.limit };
+  }
+
+  private normalizeCursorOrderBy(orderBy: any): Record<string, 'asc' | 'desc'> {
+    const entries = (Array.isArray(orderBy) ? orderBy : [orderBy]).flatMap(
+      (part) => Object.entries(part || {}),
+    );
+    const normalized: Record<string, 'asc' | 'desc'> = {};
+    for (const [field, direction] of entries) {
+      const dir = String(direction).toLowerCase();
+      if (dir !== 'asc' && dir !== 'desc') {
+        throw new BadRequestException('cursor pagination supports only asc or desc orderBy directions');
+      }
+      normalized[field] = dir;
+    }
+    if (!Object.keys(normalized).length) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (!(this.crudConfig.id_field in normalized)) {
+      normalized[this.crudConfig.id_field] = 'asc';
+    }
+    return normalized;
+  }
+
+  private decodeCursor(cursor: string, orderBy: Record<string, 'asc' | 'desc'>) {
+    let payload: Record<string, any>;
+    try {
+      if (
+        !/^(?:[A-Za-z0-9+/]{4})*(?:[A-Za-z0-9+/]{2}==|[A-Za-z0-9+/]{3}=)?$/.test(
+          cursor,
+        )
+      ) {
+        throw new Error('invalid base64');
+      }
+      payload = JSON.parse(Buffer.from(cursor, 'base64').toString('utf8'));
+      if (!payload || Array.isArray(payload) || typeof payload !== 'object') {
+        throw new Error('invalid cursor payload');
+      }
+    } catch {
+      throw new BadRequestException('cursor must be Base64-encoded JSON');
+    }
+
+    const sort = Object.entries(orderBy)
+      .map(([field, dir]) => `${field}:${dir}`)
+      .join(',');
+    if (payload.__sort !== sort) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    if (!Object.prototype.hasOwnProperty.call(payload, this.crudConfig.id_field)) {
+      throw new BadRequestException('cursor is missing the entity ID');
+    }
+    for (const field of Object.keys(orderBy)) {
+      if (!Object.prototype.hasOwnProperty.call(payload, field)) {
+        throw new BadRequestException(`cursor is missing sort field ${field}`);
+      }
+    }
+    return payload;
+  }
+
+  private getKeysetQuery(
+    orderBy: Record<string, 'asc' | 'desc'>,
+    cursor: Record<string, any>,
+  ) {
+    const fields = Object.keys(orderBy);
+    return {
+      $or: fields.map((field, index) => {
+        const clause: Record<string, any> = {};
+        for (const previous of fields.slice(0, index)) {
+          clause[previous] = cursor[previous];
+        }
+        clause[field] = { [orderBy[field] === 'asc' ? '$gt' : '$lt']: cursor[field] };
+        return clause;
+      }),
+    };
+  }
+
+  private encodeCursor(entity: T, orderBy: Record<string, 'asc' | 'desc'>) {
+    const cursor: Record<string, any> = {};
+    for (const field of Object.keys(orderBy)) {
+      cursor[field] = entity[field];
+    }
+    cursor.__sort = Object.entries(orderBy)
+      .map(([field, dir]) => `${field}:${dir}`)
+      .join(',');
+    return Buffer.from(JSON.stringify(cursor)).toString('base64');
+  }
